class Solution(object):
    def lexicographicallySmallestString(self, s):
        """
        :type s: str
        :rtype: str
        """
        n = len(s)

        def is_consecutive(a, b):
            """Check if characters are consecutive (circular alphabet)"""
            return abs(ord(a) - ord(b)) == 1 or (a == 'z' and b == 'a') or (a == 'a' and b == 'z')

        # DP: can_remove[i][j] = can all characters in s[i:j+1] be removed?
        can_remove = [[False] * n for _ in range(n)]

        # Fill DP table
        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if is_consecutive(s[i], s[j]):
                    if length == 2:
                        can_remove[i][j] = True
                    elif can_remove[i+1][j-1]:
                        can_remove[i][j] = True

        # DP: dp[i] = lexicographically smallest string from position i onwards
        memo = {}

        def dp(i):
            """Return lex smallest string starting from position i"""
            if i == n:
                return ""

            if i in memo:
                return memo[i]

            # Option 1: Keep s[i]
            result = s[i] + dp(i + 1)

            # Option 2: Remove substring s[i:j+1] if possible
            for j in range(i + 1, n):
                if can_remove[i][j]:
                    candidate = dp(j + 1)
                    if candidate < result:
                        result = candidate

            memo[i] = result
            return result

        return dp(0)
